1	/**
2	 * Rule Proposer — 固定機能.
3	 *
4	 * 5 分おきに「新しいチャット発言フック rule を提案するか」を AI に問う.
5	 * 既存の rule engine (default-tick) とは独立. tick で chat post する役割と
6	 * 「rule そのものを増やす」役割を分離して、 後者専用の loop を持つ.
7	 *
8	 * 出力 action: add_rule | skip のみ受け付ける. (post / remove は engine 側).
9	 */
10	
11	import type { RulesRepo } from "../db/rules-repo.js";
12	import type { SessionsRepo } from "../db/sessions-repo.js";
13	import type { ChatRepo } from "../db/chat-repo.js";
14	import { runClaude } from "./claude-runner.js";
15	import { handleAction } from "./handler.js";
16	import { createChildLogger } from "../shared/logger.js";
17	
18	const log = createChildLogger("rule-proposer");
19	
20	const DEFAULT_TICK_MS = 5 * 60 * 1000;       // 5 分 (admin で上書き可)
21	const STARTUP_DELAY_MS = 30 * 1000;  // 起動 30 秒後に初回
22	
23	export interface ProposerDeps {
24	  rules: RulesRepo;
25	  sessions: SessionsRepo;
26	  chat: ChatRepo;
27	  /** test 用. true で claude CLI を呼ばずスキップ. */
28	  disable_claude?: boolean;
29	  /** enabled な ai 由来 rule 数がこれ以上なら新規提案を skip (rule 雪だるま防止). */
30	  maxAiRules?: number;
31	  /**
32	   * Runtime kill-switch (AdminState.getRulesEnabled() の否定を期待).
33	   * true で runOnce が claude を呼ばず skip する.
34	   */
