import { describe, it, expect } from "vitest";
import Database from "better-sqlite3";
import { SessionsRepo } from "../src/db/sessions-repo.js";

describe("session paused flag", () => {
  let db: Database.Database;
  let repo: SessionsRepo;

  beforeEach(() => {
    db = new Database(":memory:");
    db.pragma("journal_mode = WAL");
    db.pragma("foreign_keys = ON");
    repo = new SessionsRepo(db);

    // minimal schema for test
    db.exec(`
      CREATE TABLE sessions (
        id TEXT PRIMARY KEY,
        provider TEXT NOT NULL,
        repo_path TEXT NOT NULL,
        repo_origin TEXT,
        branch TEXT,
        host TEXT NOT NULL,
        started_at INTEGER NOT NULL,
        ended_at INTEGER,
        status TEXT NOT NULL,
        last_seen_at INTEGER NOT NULL,
        current_task TEXT,
        transcript_path TEXT,
        metadata TEXT,
        ws_clients INTEGER NOT NULL DEFAULT 0,
        paused INTEGER NOT NULL DEFAULT 0
      )
    `);
  });

  it("paused defaults to 0", () => {
    repo.insertSession({
      id: "test-1",
      provider: "claude-code",
      repo_path: "/repo",
      repo_origin: null,
      branch: null,
      host: "local",
      started_at: 1000,
      last_seen_at: 1000,
      transcript_path: null,
      metadata: null,
    });

    const session = repo.findSession("test-1");
    expect(session?.paused).toBe(0);
  });

  it("setPaused sets paused flag to 1", () => {
    repo.insertSession({
      id: "test-2",
      provider: "claude-code",
      repo_path: "/repo",
      repo_origin: null,
      branch: null,
      host: "local",
      started_at: 1000,
      last_seen_at: 1000,
      transcript_path: null,
      metadata: null,
    });

    repo.setPaused("test-2", true);
    const session = repo.findSession("test-2");
    expect(session?.paused).toBe(1);
  });

  it("setPaused sets paused flag to 0", () => {
    repo.insertSession({
      id: "test-3",
      provider: "claude-code",
      repo_path: "/repo",
      repo_origin: null,
      branch: null,
      host: "local",
      started_at: 1000,
      last_seen_at: 1000,
      transcript_path: null,
      metadata: null,
    });

    repo.setPaused("test-3", true);
    repo.setPaused("test-3", false);
    const session = repo.findSession("test-3");
    expect(session?.paused).toBe(0);
  });

  it("listSessions includes paused flag", () => {
    repo.insertSession({
      id: "test-4",
      provider: "claude-code",
      repo_path: "/repo",
      repo_origin: null,
      branch: null,
      host: "local",
      started_at: 1000,
      last_seen_at: 1000,
      transcript_path: null,
      metadata: null,
    });

    repo.setPaused("test-4", true);
    const sessions = repo.listSessions({});
    expect(sessions).toHaveLength(1);
    expect(sessions[0].paused).toBe(1);
  });
});

