// セッション一時停止フラグの read/write API.
app.get("/v1/admin/sessions/:id/paused", (c) => {
  const id = c.req.param("id");
  const session = deps.repo.findSession(id);
  if (!session) return c.json({ error: "not_found" }, 404);
  return c.json({ paused: session.paused === 1 });
});

app.put("/v1/admin/sessions/:id/paused", async (c) => {
  const id = c.req.param("id");
  const session = deps.repo.findSession(id);
  if (!session) return c.json({ error: "not_found" }, 404);
  const body = await c.req.json().catch(() => null);
  if (typeof body?.paused !== "boolean") {
    return c.json({ error: "body.paused (boolean) required" }, 400);
  }
  deps.repo.setPaused(id, body.paused);
  return c.json({ paused: body.paused });
});
